const swimmer: CanSwim = { swim: () => console.log("swimming") };
const flyer: CanFly   = { fly:  () => console.log("flying") };

class Duck implements CanWalk, CanSwim, CanFly {
  constructor(
    private walking = walker,   // інжектимо поведінку
    private swimming = swimmer,
    private flying = flyer,
  ) {}
  walk() { this.walking.walk(); }
  swim() { this.swimming.swim(); }
  fly()  { this.flying.fly(); }
}
